// Approach 1: Two Pointers (Two Pointers lesson) -- REQUIRES a sorted array
// left/right pointers converge from opposite ends: O(n) time, O(1) extra space

// Approach 2: Hashing (Hashing lesson) -- works on UNSORTED arrays
// HashSet tracks seen values, checking target - num as we go: O(n) time, O(n) space

// Approach 3: Brute force (mentioned in both lessons as the baseline)
// nested loops checking every pair: O(n^2) time, O(1) space -- what we're improving on

import java.util.HashSet;
import java.util.Set;

public class Main {
    static int longestUniqueSubstring(String s) {
        Set<Character> window = new HashSet<>();
        int left = 0;
        int maxLength = 0;

        for (int right = 0; right < s.length(); right++) {
            char c = s.charAt(right);
            while (window.contains(c)) {
                window.remove(s.charAt(left));
                left++;
            }
            window.add(c);
            maxLength = Math.max(maxLength, right - left + 1);
        }
        return maxLength;
    }

    public static void main(String[] args) {
        System.out.println(longestUniqueSubstring("abcabcbb"));
    }
}

